module.render:
const layout = (args.layout || 'updown').toLowerCase() === 'right' ? 'right' : 'updown';
const color = args.color || 'var(--accent-color)';
const fontSize = args.fontSize || '0.9em';
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
// Module render runs without the markdown engine, so support the common inline
// Markdown in node labels ourselves: `code`, **bold**, *italic*, [text](url).
const inline = (s) => esc(s)
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '<em>$1</em>')
  .replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, '<a href="$2">$1</a>');

// Parse the nested bullet list (indentation = depth) into a forest.
const items = [];
for (const raw of String(content || '').split('\n')) {
  const m = raw.match(/^(\s*)(?:[-*+]|\d+\.)\s+(.*\S)\s*$/);
  if (!m) continue;
  const indent = m[1].replace(/\t/g, '  ').length;
  items.push({ indent, label: m[2].trim() });
}
if (!items.length) return `<div class="mdp-mod-tree-empty">(empty tree — provide a nested bullet list)</div>`;

const roots = [];
const stack = [{ indent: -1, node: { children: roots } }];
for (const it of items) {
  const node = { label: it.label, children: [] };
  while (stack.length > 1 && it.indent <= stack[stack.length - 1].indent) stack.pop();
  stack[stack.length - 1].node.children.push(node);
  stack.push({ indent: it.indent, node });
}

const renderNode = (node) => {
  const kids = node.children.length ? `<ul>${node.children.map(renderNode).join('')}</ul>` : '';
  return `<li><span class="mdp-tree-node">${inline(node.label)}</span>${kids}</li>`;
};
const list = `<ul>${roots.map(renderNode).join('')}</ul>`;
return `\n\n<div class="mdp-mod-tree mdp-tree-${layout}" style="--tree-color:${color}; --tree-font:${fontSize};">${list}</div>\n\n`;
